SELECT v.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cd_evt.code_label AS erp_voucher_type_cd_nm, cd_evs.code_label AS erp_voucher_status_cd_nm FROM st_erp_voucher v LEFT JOIN sy_site ste ON ste.site_id = v.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = v.vendor_id LEFT JOIN sy_code cd_evt ON cd_evt.code_grp = 'ERP_VOUCHER_TYPE' AND cd_evt.code_value = v.erp_voucher_type_cd LEFT JOIN sy_code cd_evs ON cd_evs.code_grp = 'ERP_VOUCHER_STATUS' AND cd_evs.code_value = v.erp_voucher_status_cd
ORDER BY v.erp_voucher_id ASC ORDER BY v.erp_voucher_id DESC ORDER BY v.settle_ym ASC ORDER BY v.settle_ym DESC ORDER BY v.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

SELECT v.*, ste.site_nm AS site_nm, vnd.vendor_nm AS vendor_nm, cd_evt.code_label AS erp_voucher_type_cd_nm, cd_evs.code_label AS erp_voucher_status_cd_nm FROM st_erp_voucher v LEFT JOIN sy_site ste ON ste.site_id = v.site_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = v.vendor_id LEFT JOIN sy_code cd_evt ON cd_evt.code_grp = 'ERP_VOUCHER_TYPE' AND cd_evt.code_value = v.erp_voucher_type_cd LEFT JOIN sy_code cd_evs ON cd_evs.code_grp = 'ERP_VOUCHER_STATUS' AND cd_evs.code_value = v.erp_voucher_status_cd
ORDER BY v.erp_voucher_id ASC ORDER BY v.erp_voucher_id DESC ORDER BY v.settle_ym ASC ORDER BY v.settle_ym DESC ORDER BY v.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

