UPDATE st_erp_voucher
site_id = #{siteId}, vendor_id = #{vendorId}, settle_id = #{settleId}, settle_ym = #{settleYm}, erp_voucher_type_cd = #{erpVoucherTypeCd}, erp_voucher_status_cd = #{erpVoucherStatusCd}, erp_voucher_status_cd_before = #{erpVoucherStatusCdBefore}, voucher_date = #{voucherDate}, erp_voucher_desc = #{erpVoucherDesc}, total_debit_amt = #{totalDebitAmt}, total_credit_amt = #{totalCreditAmt}, erp_send_date = #{erpSendDate}, erp_voucher_no = #{erpVoucherNo}, erp_res_msg = #{erpResMsg}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE erp_voucher_id = #{erpVoucherId}
